var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"48시간 전.","JPN":"48時間前。","ENG":"48 hours ago.","TWN":"48小時前。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"북방합의체 영토권- 시베리아 중부, 봉쇄 균열.","JPN":"北方合意体の領土圏 - シベリア中部、封鎖亀裂。","ENG":"Northern Union Territory- Central Siberia, Sealed Crevice.","TWN":"北方和議會領土 - 西伯利亞中部，峽谷封鎖處。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 지정 코드명- <color=#ffd34c>그라운드 제로</color>","JPN":"管理局指定コードネーム - <color=#ffd34c>グラウンド・ゼロ</color>","ENG":"Administration-appointed Codename- <color=#ffd34c>Ground Zero</color>","TWN":"管理局命名代號 - <color=#ffd34c>G0</color>"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그라운드 제로는 시베리아 한복판에 운석 구덩이처럼 생긴 균열을 일컫는 말이지.","JPN":"グラウンド・ゼロは、シベリアの真ん中にある隕石のくぼみみたいな亀裂を示す言葉だよ。","ENG":"Ground Zero refers to the Crevice that looks like a meteorite crater in the middle of Siberia.","TWN":"G0指的是西伯利亞正中央隕石坑形狀的峽谷。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"관리국의 손길이 안 닿는 지금은 북방합의체의 군이 멋대로 관리하는 중이야.","JPN":"管理局の手が届かない今は、北方合意体の軍が勝手に管理してる。","ENG":"With the Administration out of its reach, the Northern Union's army is managing it as they please.","TWN":"因為管理局的手還無法觸及這裡，所以現在還是由北方和議會的軍隊掌控。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그리고 우리 앞을 가로막는 이 큰 벽은 합의체가 개발한 <color=#ffd34c>밸브</color>란 장치다.","JPN":"そして私たちの前に立ちふさがるこの大きな壁は、合意体が開発した<color=#ffd34c>バルブ</color>って装置。","ENG":"And the big wall blocking our path is a device the Northern Union developed called the <color=#ffd34c>Valve</color>.","TWN":"而擋在我們面前的這堵厚牆，是由北方和議會開發的<color=#ffd34c>閥門</color>裝置。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"외부인의 출입을 차단하는 동시에, 균열에서 흘러나오는 침식파가 외부로 새어나가지 못하도록 막아준다고 해.","JPN":"よそ者の出入りを遮断するのと同時に、亀裂から漏れる侵食波が外に出ないように塞ぐらしいよ。","ENG":"It blocks the entry of outsiders while also preventing the Corruption ray that is flowing out the Crevice from leaking to the outside.","TWN":"能夠在阻止外來人員進入的同時，防止從峽谷中流出的侵蝕波散佈到外界。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"언제까지 의미없는 독백만 하고 있을 셈이냐.","JPN":"いつまで意味のない独り言を言っているつもりだ？","ENG":"How much longer are you going to keep up with these meaningless monologues?","TWN":"你打算一個人獨白到什麼時候？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"네 입으로 문은 금방 열 거라고 하지 않았던가?","JPN":"お前の口からは、扉はすぐに開くと言っていなかったか？","ENG":"Didn't you tell me that you could open that door in seconds?","TWN":"不是說門很快就會打開嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"아하하, 잠깐만 기다려…","JPN":"あはは、ちょっと待って……","ENG":"Ah hah hah. Just give me a sec...","TWN":"哈哈哈，再給我幾分鐘……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이상하다. 전에 왔을 땐 이런 무식한 기계식 자물쇠는 없었는데?","JPN":"おかしいな。前に来た時にはこんな機械式の錠なんてなかったんだけど。","ENG":"That's odd. There wasn't this stupid mechanical lock the last time I was here.","TWN":"奇怪。之前來的時候沒有這種笨重的機械鎖啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"더 싼 경비 업체로 바뀐 건가?","JPN":"もっと安い警備会社に変えたのかな？","ENG":"Did they switch vendors to a cheaper one?","TWN":"換成更便宜的保安公司了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"아무튼 조금만 기다려. 내가 어떻게든 열어볼…","JPN":"とにかく、ちょっとだけ待ってて。私が何とか開けてみ……","ENG":"Give me just a second. I'll get it open–","TWN":"總之稍等一下。我會想辦法打開的……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"시간 없다. 비켜.","JPN":"時間がない。どけ。","ENG":"No time. Step aside.","TWN":"沒時間了，讓開。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"야…! 잠깐 기다려. 네 방식대로 움직이면 항상 일이…!","JPN":"ちょっと……！　待ってよ。あなたのやり方だと、いつも事態が……！","ENG":"Hey...! I said, give me a second. Things always go south if we do it your–!","TWN":"喂……！等一下。每次按照你的方式行動，事情總是會鬧得……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…커진다고…","JPN":"……大きくなるんだってば……","ENG":"...way...","TWN":"……更大……"},"stage":{"bg":"LIFT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"문을 지키는 병사라기엔 병력 숫자가 좀 많은데?","JPN":"扉を守るにしては、兵士の数がちょっと多すぎない？","ENG":"Don't you think that's a lot of soldiers just to guard a door?","TWN":"感覺……守門的士兵數量好像有點多啊？"},"stage":{"bg":"SKY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"당황하지 않는군. 우리가 올 줄 알고 있었던 거다.","JPN":"慌てる様子もないな。私たちが来るとわかっていたのだ。","ENG":"They're not panicking. They knew we were coming.","TWN":"他們一點也不慌張。看來早就知道我們會來了。"},"stage":{"bg":"SKY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"하하… 괜찮아. 허튼짓만 안하면 당장 쏘진 않을 거야.","JPN":"はは……大丈夫だよ。余計なことしなければすぐ撃ってきたりはしないよ。","ENG":"Haha... It's fine. They won't shoot as long as we don't do anything rash.","TWN":"哈、哈……沒關係。只要不胡鬧，他們不會馬上開槍的。"},"stage":{"bg":"SKY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"우리 꼴을 봐. 그냥 길 잃은 애들인 척 울면서 적당히 연기하면…","JPN":"私たちのこの姿を見て。迷子のふりして、泣きながら適当に演技でもすれば……","ENG":"I mean, just look at us. If we pretend to be lost kids, then–","TWN":"我的意思是，只要裝作迷路的樣子，再假惺惺地哭一下……"},"stage":{"bg":"SKY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"키야아악!","JPN":"きゃああっ！","ENG":"KYAAAAH!","TWN":"呀！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"갑자기 총은 왜 쏘는 거야!! 미쳤나 봐!!!","JPN":"いきなりなんで撃つのよ！！　どうかしてんじゃない！！？","ENG":"Did they just shoot at us?! You've got to be kidding me!!!","TWN":"為什麼突然射擊？！你們瘋了嗎！！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"패러독스! 내 기억이 여기에 있는 게 확실하겠지?","JPN":"パラドックス！　私の記憶がここにあるということは確かなんだな？","ENG":"Paradox! You're sure that my memories are here, right?","TWN":"悖論！我的記憶確定是在這裡嗎！？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내가 놈들을 막는 동안 넌 어서 <color=#ffd34c>그걸</color> 연결해라!","JPN":"私がこいつらを食い止めている間に、お前は早く<color=#ffd34c>それ</color>を繋げろ！","ENG":"While I stop them, you go ahead and connect <color=#ffd34c>that thing</color>!","TWN":"我來擋住他們，你快去把<color=#ffd34c>那東西</color>連上！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그거? 동앗줄 말이야? 무리야! 안돼! 그거 엄청 집중력이 필요한 일이라구우!","JPN":"それ？　縄のこと？　無理！　ダメ！　それ、めっちゃ集中力が要るんだって！","ENG":"That thing? You mean Straw Rope? Nuh-uh! Never! That requires super focus, you know!","TWN":"那東西？你是說繩嗎？不行！絕對不行！那可是需要極高集中力的工作啊！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"죽기 싫으면 잔말 말고 서둘러!","JPN":"死にたくなければ、さっさと急げ！","ENG":"Do as I say if you don't want to die!","TWN":"不想死就別囉嗦，快點！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"}]`);export{e as default};